import{_ as f}from"./D0lMb-6t.js";import{u as n}from"./CYcTZJ76.js";import{l as r,U as e,Q as s,g as p,k as c,i as u,d as t,B as m}from"./CEACHmc7.js";import{_ as v}from"./DlAUqK2U.js";import"./DRz8eFSk.js";const h=r({__name:"o-proekte",setup(_){n({title:"О проекте «Время Есть»: методология и источники данных",description:"Как мы подбираем рецепты, откуда берём КБЖУ, почему без фотографий блюд и как нас можно проверить.",path:"/o-proekte",ogSlug:"about"});const{siteUrl:o}=e().public;s({script:[{type:"application/ld+json",children:JSON.stringify({"@context":"https://schema.org","@type":"Organization",name:"Время Есть",url:o,logo:`${o}/og/default.png`,email:"hi@plus-time.ru",description:"Сервис планирования домашнего питания: меню на неделю, список покупок и собственная библиотека рецептов.",sameAs:[]})}]});function l(){if(typeof window<"u"&&typeof window.ym=="function"){const d=e().public.ymCounter;d&&window.ym(d,"reachGoal","clicked_cta_from_about")}}return(d,a)=>{const i=f;return m(),p("article",null,[c(i,{items:[{label:"Главная",to:"/"},{label:"О проекте"}]}),a[1]||(a[1]=u('<h1 data-v-08f0d084>О «Время Есть»: методология, источники, ответственность</h1><p class="lead" data-v-08f0d084> «Время Есть» — это сервис планирования домашнего питания. За 60 секунд мы собираем персональное меню на неделю и готовый список покупок. Свои рецепты тоже можно добавить и сохранить. Эта страница объясняет, как именно мы это делаем — потому что доверие к сервису о еде нельзя строить на «нам можно верить». </p><h2 data-v-08f0d084>Кто стоит за проектом</h2><p data-v-08f0d084> «Время Есть» делает небольшая команда — мы не выдаём себя за коллектив дипломированных нутрициологов. Решения принимаем на основе открытых источников и тестируем рекомендации на собственных кухнях. Если у тебя в семье — медицинские диеты или аллергии, наши меню стоит дополнительно согласовать с твоим врачом. Это касается всего сервиса. </p><h2 data-v-08f0d084>Откуда берём калории, белки, жиры и углеводы</h2><ul data-v-08f0d084><li data-v-08f0d084> Для базовых продуктов — таблицы Роспотребнадзора («Химический состав пищевых продуктов»), действующая редакция. </li><li data-v-08f0d084> Для импортных позиций — открытая база <a href="https://fdc.nal.usda.gov/" rel="nofollow" data-v-08f0d084>USDA FoodData Central</a>. </li><li data-v-08f0d084> Для составных рецептов — пересчёт КБЖУ из ингредиентов по массе с учётом потерь при тепловой обработке (коэффициенты Минздрава для разных типов готовки). </li></ul><p data-v-08f0d084> Это значит: КБЖУ на нашем сайте — справочная информация, а не клиническая. Погрешность 5–10% — обычное дело для домашних рецептов, потому что реальная масса лука или мяса всегда чуть отличается от номинальной. </p><h2 data-v-08f0d084>Как мы подбираем рецепты для меню</h2><ol data-v-08f0d084><li data-v-08f0d084> Алгоритм собирает 7-дневное меню так, чтобы среднесуточные КБЖУ соответствовали твоим целям (поддержание/снижение/набор), приёмы пищи чередовали белки/углеводы, а ингредиенты переиспользовались между днями для меньшего списка покупок. </li><li data-v-08f0d084> Учитываем диеты (ПП, вегетарианское, без глютена), аллергии, состав семьи и бюджет. Эти параметры собираются в коротком онбординге. </li><li data-v-08f0d084> Все рецепты тестируются перед попаданием в каталог. Если что-то не получается даже у нас — переписываем шаги или убираем рецепт. Это часть процесса, не реклама. </li></ol><h2 data-v-08f0d084>Почему на сайте нет «авторских» фотографий блюд</h2><p data-v-08f0d084> Сделать собственные качественные фото 2 000+ рецептов — задача не на одного человека. Стоковые фото мы решили не покупать: они часто выглядят постановочно и не имеют отношения к конкретному рецепту. Вместо этого каждая карточка использует эмодзи и цветовой код приёма пищи — это узнаваемо, быстро грузится на телефоне и не вводит в заблуждение. Когда дойдём до собственной съёмки — будем добавлять реальные снимки готовых блюд из наших кухонь, а не из фотобанка. </p><h2 data-v-08f0d084>Как ты можешь нам не верить</h2><p data-v-08f0d084> Это правильный вопрос. Мы рекомендуем не верить, а проверять: </p><ul data-v-08f0d084><li data-v-08f0d084>КБЖУ можно сверить по ссылкам на USDA / Роспотребнадзор выше.</li><li data-v-08f0d084>Список покупок мы не передаём третьим сторонам — он остаётся в твоём аккаунте.</li><li data-v-08f0d084>Свои рецепты, добавленные в личном кабинете, доступны только тебе.</li></ul><h2 data-v-08f0d084>Связаться</h2><p data-v-08f0d084> Заметил ошибку в рецепте или КБЖУ? Не работает фича в приложении? Пиши на <a href="mailto:hi@plus-time.ru" data-v-08f0d084>hi@plus-time.ru</a>. Мы отвечаем — обычно в течение рабочего дня. </p>',16)),t("div",{class:"cta-block"},[a[0]||(a[0]=t("p",null,[t("strong",null,"Готов попробовать?")],-1)),t("a",{href:"/",class:"btn-cta",onClick:l},"Составить меню за 60 сек")])])}}}),S=v(h,[["__scopeId","data-v-08f0d084"]]);export{S as default};
